<script setup lang="ts">
/* eslint vue/singleline-html-element-content-newline: "off", vue/max-attributes-per-line: "off", vue/html-self-closing: "off" */
import { computed, onMounted, reactive, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ArrowLeft, Banknote, CalendarClock, CreditCard, Dumbbell, Pencil, Plus, Save, ShieldAlert, Waves } from 'lucide-vue-next'
import InitialsAvatar from '@/components/InitialsAvatar.vue'
import StatePanel from '@/components/StatePanel.vue'
import StatusBadge from '@/components/StatusBadge.vue'
import { apiFetch, money, shortDate } from '@/lib/api'
import { useAuthStore } from '@/stores/auth'

interface Plan { id:string; name:string; durationDays:number; priceCents:number; poolAccess:boolean; gymAccess:boolean }
interface Membership { id:string; planId:string; planName:string; durationDays:number; poolAccess:boolean; gymAccess:boolean; status:string; startsOn:string; endsOn:string; saleAmountCents:number; debtTotalCents:number; paidTotalCents:number; balanceCents:number; lastPaidAt?:string; notes?:string }
interface Payment { id:string; membershipId?:string; enrollmentId?:string; planName?:string; courseName?:string; amountCents:number; method:string; status:string; paidAt:string; receiptNumber?:string; reference?:string; note?:string; recordedBy:string }
interface StatementItem { id:string;kind:string;source:string;description:string;amountCents:number;direction:'charge'|'payment';status:string;occurredAt:string;subjectId:string;method?:string;receiptNumber?:string;reference?:string;recordedBy?:string;voidReason?:string }
interface Detail { participant:{id:string;participantType:string;firstName:string;lastName:string;fullName:string;birthDate?:string;email?:string;phone?:string;emergencyContactName?:string;emergencyContactPhone?:string;swimmingLevel?:string;safetyNotes?:string;guardian?:{fullName:string;relationship?:string;phone:string;email?:string}|null}; memberships:Membership[]; membershipPayments:Payment[]; membershipDebts:Array<{id:string;membershipId:string;planName:string;amountCents:number;reason:string;dueOn?:string;status:string;createdAt:string;recordedBy:string}>; enrollments:Array<{id:string;courseId:string;courseName:string;status:string;agreedFeeAmountCents:number;paidTotalCents:number;balanceCents:number;registeredAt:string}>; coursePayments:Payment[]; financeStatement:StatementItem[]; summary:{membershipPaidTotalCents:number;membershipBalanceCents:number;courseBalanceCents:number} }

const route=useRoute(); const router=useRouter(); const auth=useAuthStore(); const participantId=String(route.params.participantId)
const detail=ref<Detail|null>(null); const plans=ref<Plan[]>([]); const loading=ref(true); const saving=ref(false); const error=ref(''); const notice=ref(''); const editMode=ref(false); const showPackage=ref(false); const showPayment=ref(false); const showDebt=ref(false)
const profile=reactive({firstName:'',lastName:'',phone:'',email:'',birthDate:'',emergencyContactName:'',emergencyContactPhone:'',swimmingLevel:'',safetyNotes:''})
const packageForm=reactive({planId:'',startsOn:new Date().toISOString().slice(0,10),initialPaymentTl:0,paymentMethod:'cash',note:''})
const paymentForm=reactive({membershipId:'',amountTl:0,method:'cash',reference:'',note:''})
const debtForm=reactive({membershipId:'',amountTl:0,dueOn:'',reason:''})
const selectedPlan=computed(()=>plans.value.find((plan)=>plan.id===packageForm.planId)); const packageRemainingCents=computed(()=>Math.max(0,(selectedPlan.value?.priceCents??0)-Math.round(Number(packageForm.initialPaymentTl||0)*100))); const payableMemberships=computed(()=>detail.value?.memberships.filter((membership)=>membership.balanceCents>0)??[]); const adjustableMemberships=computed(()=>detail.value?.memberships.filter((membership)=>['active','frozen'].includes(membership.status))??[])
const statementRows=computed(()=>{let balance=0;return [...(detail.value?.financeStatement??[])].sort((a,b)=>new Date(a.occurredAt).getTime()-new Date(b.occurredAt).getTime()).map((item)=>{if(item.status==='recorded')balance+=item.direction==='charge'?item.amountCents:-item.amountCents;return {...item,balanceCents:balance}}).reverse()})
const statusLabel:Record<string,string>={active:'Aktif',frozen:'Dondurulmuş',expired:'Süresi doldu',cancelled:'İptal'}
const statusTone:Record<string,'success'|'warning'|'danger'|'neutral'>={active:'success',frozen:'warning',expired:'neutral',cancelled:'danger'}
const paymentMethod:Record<string,string>={cash:'Nakit',card_terminal:'Kart',bank_transfer:'Havale/EFT',other:'Diğer'}

function populateForm(){if(!detail.value)return;const person=detail.value.participant;Object.assign(profile,{firstName:person.firstName,lastName:person.lastName,phone:person.phone||'',email:person.email||'',birthDate:person.birthDate||'',emergencyContactName:person.emergencyContactName||'',emergencyContactPhone:person.emergencyContactPhone||'',swimmingLevel:person.swimmingLevel||'',safetyNotes:person.safetyNotes||''})}
async function load(){loading.value=true;error.value='';try{const [response,options]=await Promise.all([apiFetch<Detail>(`/participants/${participantId}`),apiFetch<{plans:Plan[]}>('/memberships/options')]);detail.value=response;plans.value=options.plans;if(!packageForm.planId&&plans.value[0])packageForm.planId=plans.value[0].id;populateForm()}catch(cause){error.value=cause instanceof Error?cause.message:'Üye detayı yüklenemedi.'}finally{loading.value=false}}
async function saveProfile(){saving.value=true;notice.value='';try{await apiFetch(`/participants/${participantId}`,{method:'PATCH',body:JSON.stringify({firstName:profile.firstName,lastName:profile.lastName,phone:profile.phone||null,email:profile.email||null,birthDate:profile.birthDate||null,emergencyContactName:profile.emergencyContactName||null,emergencyContactPhone:profile.emergencyContactPhone||null,swimmingLevel:profile.swimmingLevel||null,safetyNotes:profile.safetyNotes||null})});editMode.value=false;notice.value='Üye bilgileri güncellendi.';await load()}catch(cause){error.value=cause instanceof Error?cause.message:'Bilgiler güncellenemedi.'}finally{saving.value=false}}
async function addPackage(){if(!detail.value||!packageForm.planId)return;saving.value=true;notice.value='';try{await apiFetch('/memberships',{method:'POST',body:JSON.stringify({participantId,planId:packageForm.planId,startsOn:packageForm.startsOn,initialPaymentCents:Math.round(Number(packageForm.initialPaymentTl||0)*100),paymentMethod:packageForm.paymentMethod,note:packageForm.note||null})});showPackage.value=false;packageForm.initialPaymentTl=0;packageForm.note='';notice.value='Yeni paket üyeye eklendi; kalan bakiye otomatik hesaplandı.';await load()}catch(cause){error.value=cause instanceof Error?cause.message:'Paket eklenemedi.'}finally{saving.value=false}}
async function addPayment(){if(!paymentForm.membershipId||Number(paymentForm.amountTl)<=0)return;saving.value=true;notice.value='';try{await apiFetch(`/memberships/${paymentForm.membershipId}/payments`,{method:'POST',body:JSON.stringify({amountCents:Math.round(Number(paymentForm.amountTl)*100),method:paymentForm.method,reference:paymentForm.reference||null,note:paymentForm.note||null})});showPayment.value=false;paymentForm.amountTl=0;paymentForm.reference='';paymentForm.note='';notice.value='Tahsilat kaydedildi; bakiye özeti yenilendi.';await load()}catch(cause){error.value=cause instanceof Error?cause.message:'Tahsilat kaydedilemedi.'}finally{saving.value=false}}
async function addDebt(){if(!debtForm.membershipId||Number(debtForm.amountTl)<=0||debtForm.reason.trim().length<3)return;saving.value=true;notice.value='';try{await apiFetch(`/memberships/${debtForm.membershipId}/debts`,{method:'POST',body:JSON.stringify({amountCents:Math.round(Number(debtForm.amountTl)*100),reason:debtForm.reason.trim(),dueOn:debtForm.dueOn||null})});showDebt.value=false;debtForm.amountTl=0;debtForm.dueOn='';debtForm.reason='';notice.value='Ek ücret kaydedildi; bakiye özeti yenilendi.';await load()}catch(cause){error.value=cause instanceof Error?cause.message:'Ek ücret kaydedilemedi.'}finally{saving.value=false}}
async function cancelMembership(membership:Membership){const reason=globalThis.prompt('Üyelik iptal nedeni:');if(!reason?.trim())return;saving.value=true;notice.value='';try{await apiFetch(`/memberships/${membership.id}/cancel`,{method:'POST',body:JSON.stringify({reason:reason.trim()})});notice.value='Üyelik iptal edildi; tahsilat geçmişi ve açık bakiye korundu.';await load()}catch(cause){error.value=cause instanceof Error?cause.message:'Üyelik iptal edilemedi.'}finally{saving.value=false}}
function openPayment(membership:Membership){paymentForm.membershipId=membership.id;paymentForm.amountTl=membership.balanceCents/100;showPayment.value=true}
function openDebt(membership:Membership){debtForm.membershipId=membership.id;debtForm.amountTl=0;debtForm.dueOn='';debtForm.reason='';showDebt.value=true}
onMounted(load)
</script>

<template>
  <StatePanel v-if="loading" state="loading" />
  <StatePanel v-else-if="error&&!detail" state="error" :message="error" @retry="load" />
  <template v-else-if="detail">
    <div class="member-hero"><div class="hero-person"><button class="icon-button" type="button" aria-label="Üyelik listesine dön" @click="router.push('/memberships')"><ArrowLeft :size="20" /></button><InitialsAvatar :name="detail.participant.fullName" size="lg" /><div><p class="eyebrow">Üye detayı</p><h1>{{ detail.participant.fullName }}</h1><p>{{ detail.participant.phone || detail.participant.email || 'İletişim bilgisi eklenmemiş' }}</p></div></div><div class="page-actions"><button class="button button--secondary" type="button" @click="editMode=!editMode"><Pencil :size="16" />Bilgileri düzenle</button><button class="button button--secondary" type="button" @click="showPackage=!showPackage"><Plus :size="16" />Paket ekle</button><button v-if="payableMemberships.length" class="button button--primary" type="button" @click="openPayment(payableMemberships[0])"><Banknote :size="16" />Tahsilat al</button></div></div>
    <div v-if="error" class="notice notice--danger">{{ error }}</div><div v-if="notice" class="notice notice--success">{{ notice }}</div>
    <section class="metrics-grid member-metrics"><div class="metric-card"><div><span>Aktif paket</span><strong class="metric-card__value">{{ detail.memberships.filter((m)=>m.status==='active').length }}</strong><p>Salon ve havuz erişimi</p></div><Dumbbell class="metric-card__icon" /></div><div class="metric-card" :class="{'metric-card--danger':detail.summary.membershipBalanceCents>0}"><div><span>Kalan üyelik bakiyesi</span><strong class="metric-card__value">{{ money(detail.summary.membershipBalanceCents) }}</strong><p>Tüm üyeliklerden açık alacak</p></div><CreditCard class="metric-card__icon" /></div><div class="metric-card"><div><span>Tahsil edilen</span><strong class="metric-card__value">{{ money(detail.summary.membershipPaidTotalCents) }}</strong><p>Kayıtlı üyelik ödemeleri</p></div><Banknote class="metric-card__icon" /></div><div class="metric-card" :class="{'metric-card--danger':detail.summary.courseBalanceCents>0}"><div><span>Kurs bakiyesi</span><strong class="metric-card__value">{{ money(detail.summary.courseBalanceCents) }}</strong><p>Varsa kurs kayıtları</p></div><Waves class="metric-card__icon" /></div></section>
    <section v-if="editMode" class="card form-card"><div class="card__header"><h2>Üye bilgilerini düzenle</h2></div><form class="card__body form-grid" @submit.prevent="saveProfile"><label class="field"><span>Ad</span><input v-model="profile.firstName" required /></label><label class="field"><span>Soyad</span><input v-model="profile.lastName" required /></label><label class="field"><span>Telefon</span><input v-model="profile.phone" /></label><label class="field"><span>E-posta</span><input v-model="profile.email" type="email" /></label><label class="field"><span>Doğum tarihi</span><input v-model="profile.birthDate" type="date" /></label><label class="field"><span>Yüzme seviyesi</span><input v-model="profile.swimmingLevel" /></label><label class="field"><span>Acil durum kişisi</span><input v-model="profile.emergencyContactName" /></label><label class="field"><span>Acil durum telefonu</span><input v-model="profile.emergencyContactPhone" /></label><label class="field field--full"><span>Güvenlik / operasyon notu</span><textarea v-model="profile.safetyNotes" /></label><div class="field field--full form-actions"><button class="button button--secondary" type="button" @click="editMode=false;populateForm()">Vazgeç</button><button class="button button--primary" :disabled="saving"><Save :size="16" />Kaydet</button></div></form></section>
    <section v-if="showPackage" class="card form-card"><div class="card__header"><h2>Yeni üyelik paketi</h2><span class="muted">{{ selectedPlan?money(selectedPlan.priceCents):'Paket seçin' }}</span></div><form class="card__body form-grid" @submit.prevent="addPackage"><label class="field"><span>Paket</span><select v-model="packageForm.planId"><option v-for="plan in plans" :key="plan.id" :value="plan.id">{{ plan.name }} · {{ plan.durationDays }} gün</option></select></label><label class="field"><span>Başlangıç</span><input v-model="packageForm.startsOn" type="date" required /></label><label class="field"><span>İlk tahsilat (TL)</span><input v-model.number="packageForm.initialPaymentTl" :max="(selectedPlan?.priceCents??0)/100" min="0" step="0.01" type="number" /></label><label class="field"><span>Ödeme yöntemi</span><select v-model="packageForm.paymentMethod"><option value="cash">Nakit</option><option value="card_terminal">Kart</option><option value="bank_transfer">Havale/EFT</option><option value="other">Diğer</option></select></label><div v-if="selectedPlan" class="field field--full finance-preview"><div><span>Paket bedeli</span><strong>{{ money(selectedPlan.priceCents) }}</strong></div><div><span>İlk tahsilat</span><strong>{{ money(Math.round(Number(packageForm.initialPaymentTl||0)*100)) }}</strong></div><div><span>Kalan bakiye</span><strong>{{ money(packageRemainingCents) }}</strong></div><p>Kalan bakiye otomatik oluşur; ayrıca ek ücret girmeniz gerekmez.</p></div><label class="field"><span>Erişim</span><input :value="selectedPlan?(selectedPlan.gymAccess?'Salon ':'')+(selectedPlan.poolAccess?'Havuz':''):'-'" readonly /></label><label class="field field--full"><span>Not</span><textarea v-model="packageForm.note" /></label><div class="field field--full form-actions"><button class="button button--secondary" type="button" @click="showPackage=false">Vazgeç</button><button class="button button--primary" :disabled="saving"><Plus :size="16" />Paketi ekle</button></div></form></section>
    <section v-if="showPayment" class="card form-card"><div class="card__header"><h2>Üyelik tahsilatı</h2><span class="muted">Açık bakiyeden düşülür</span></div><form class="card__body form-grid" @submit.prevent="addPayment"><label class="field"><span>Paket</span><select v-model="paymentForm.membershipId"><option v-for="membership in payableMemberships" :key="membership.id" :value="membership.id">{{ membership.planName }} · {{ money(membership.balanceCents) }} kalan</option></select></label><label class="field"><span>Tutar (TL)</span><input v-model.number="paymentForm.amountTl" min="0.01" step="0.01" type="number" required /></label><label class="field"><span>Ödeme yöntemi</span><select v-model="paymentForm.method"><option value="cash">Nakit</option><option value="card_terminal">Kart</option><option value="bank_transfer">Havale/EFT</option><option value="other">Diğer</option></select></label><label class="field"><span>Referans</span><input v-model="paymentForm.reference" /></label><label class="field field--full"><span>Not</span><textarea v-model="paymentForm.note" /></label><div class="field field--full form-actions"><button class="button button--secondary" type="button" @click="showPayment=false">Vazgeç</button><button class="button button--primary" :disabled="saving"><Banknote :size="16" />Tahsilatı kaydet</button></div></form></section>
    <section v-if="showDebt" class="card form-card"><div class="card__header"><h2>Ek ücret ekle</h2><span class="muted">Paket bedelinin dışında ek hizmet, ekipman veya fiyat farkı oluşturur.</span></div><form class="card__body form-grid" @submit.prevent="addDebt"><label class="field"><span>Paket</span><select v-model="debtForm.membershipId"><option v-for="membership in adjustableMemberships" :key="membership.id" :value="membership.id">{{ membership.planName }} · {{ money(membership.balanceCents) }} kalan</option></select></label><label class="field"><span>Ek ücret (TL)</span><input v-model.number="debtForm.amountTl" min="0.01" step="0.01" type="number" required /></label><label class="field"><span>Vade tarihi</span><input v-model="debtForm.dueOn" type="date" /></label><label class="field field--full"><span>Ücret açıklaması</span><textarea v-model="debtForm.reason" required minlength="3" placeholder="Örn. ek hizmet, ekipman veya fiyat farkı" /></label><div class="field field--full form-actions"><button class="button button--secondary" type="button" @click="showDebt=false">Vazgeç</button><button class="button button--primary" :disabled="saving"><Plus :size="16" />Ek ücreti kaydet</button></div></form></section>
    <div class="member-layout"><main class="stack"><section class="card"><div class="card__header"><h2>Üyelik paketleri</h2><span class="muted">{{ detail.memberships.length }} kayıt</span></div><div v-if="detail.memberships.length" class="membership-list"><article v-for="membership in detail.memberships" :key="membership.id" class="membership-item"><div class="membership-item__main"><div><strong>{{ membership.planName }}</strong><p>{{ shortDate(membership.startsOn) }} — {{ shortDate(membership.endsOn) }}</p></div><StatusBadge :tone="statusTone[membership.status]||'neutral'" :label="statusLabel[membership.status]||membership.status" /></div><div class="membership-item__facts"><span><Dumbbell v-if="membership.gymAccess" :size="15" />{{ membership.gymAccess?'Salon':'Salon yok' }}</span><span><Waves v-if="membership.poolAccess" :size="15" />{{ membership.poolAccess?'Havuz':'Havuz yok' }}</span><span><CalendarClock :size="15" />{{ membership.durationDays }} gün</span></div><div class="membership-item__money"><div><span>Paket bedeli</span><strong>{{ money(membership.saleAmountCents) }}</strong></div><div><span>Ek ücret</span><strong :class="{'text-danger':membership.debtTotalCents>0}">{{ money(membership.debtTotalCents) }}</strong></div><div><span>Toplam alacak</span><strong>{{ money(membership.saleAmountCents+membership.debtTotalCents) }}</strong></div><div><span>Tahsil edilen</span><strong>{{ money(membership.paidTotalCents) }}</strong></div><div><span>Kalan bakiye</span><strong :class="{'text-danger':membership.balanceCents>0}">{{ money(membership.balanceCents) }}</strong></div></div><p v-if="membership.notes" class="muted">{{ membership.notes }}</p><div class="membership-item__actions"><button v-if="['active','frozen'].includes(membership.status)" class="button button--secondary" type="button" @click="openDebt(membership)">Ek ücret ekle</button><button v-if="membership.balanceCents>0" class="button button--secondary" type="button" @click="openPayment(membership)">Tahsilat al</button><button v-if="auth.isManager&&['active','frozen'].includes(membership.status)" class="button button--danger" type="button" :disabled="saving" @click="cancelMembership(membership)"><ShieldAlert :size="16" />İptal et</button></div></article></div><StatePanel v-else state="empty" title="Üyelik paketi yok" message="Bu kişiye paket ekleyerek salon erişimini başlatın." /></section><section class="card"><div class="card__header"><h2>Üyelik tahsilat geçmişi</h2><span class="muted">Bakiye her kayıtta otomatik yenilenir</span></div><div v-if="detail.membershipPayments.length" class="table-wrap"><table class="data-table"><thead><tr><th>Tarih</th><th>Paket</th><th>Tutar</th><th>Yöntem</th><th>Durum</th></tr></thead><tbody><tr v-for="payment in detail.membershipPayments" :key="payment.id"><td>{{ shortDate(payment.paidAt) }}</td><td>{{ payment.planName }}</td><td><strong>{{ money(payment.amountCents) }}</strong></td><td>{{ paymentMethod[payment.method]||payment.method }}</td><td><StatusBadge :tone="payment.status==='recorded'?'success':'neutral'" :label="payment.status==='recorded'?'Kayıtlı':'İptal'" /></td></tr></tbody></table></div><StatePanel v-else state="empty" title="Üyelik tahsilatı yok" message="İlk tahsilatı veya sonraki ödemeleri buradan kaydedin." /></section><section class="card"><div class="card__header"><h2>Ek ücret geçmişi</h2><span class="muted">Paket bedelinden ayrı hizmet ve farklar</span></div><div v-if="detail.membershipDebts.length" class="table-wrap"><table class="data-table"><thead><tr><th>Tarih</th><th>Paket</th><th>Ek ücret</th><th>Vade</th><th>Açıklama</th></tr></thead><tbody><tr v-for="debt in detail.membershipDebts" :key="debt.id"><td>{{ shortDate(debt.createdAt) }}</td><td>{{ debt.planName }}</td><td><strong class="text-danger">{{ money(debt.amountCents) }}</strong></td><td>{{ debt.dueOn?shortDate(debt.dueOn):'—' }}</td><td>{{ debt.reason }}</td></tr></tbody></table></div><StatePanel v-else state="empty" title="Ek ücret yok" message="Paket dışı hizmet veya fark bedellerini Ek ücret ekle ile kaydedin." /></section></main><aside class="stack"><section class="card"><div class="card__header"><h2>İletişim ve veli</h2></div><div class="card__body side-facts"><div><span>Telefon</span><strong>{{ detail.participant.phone||'Eklenmemiş' }}</strong></div><div><span>E-posta</span><strong>{{ detail.participant.email||'Eklenmemiş' }}</strong></div><div><span>Acil durum</span><strong>{{ detail.participant.emergencyContactName||detail.participant.emergencyContactPhone||'Eklenmemiş' }}</strong></div><div v-if="detail.participant.guardian"><span>Veli</span><strong>{{ detail.participant.guardian.fullName }}</strong><small>{{ detail.participant.guardian.phone }}</small></div></div></section><section class="card"><div class="card__header"><h2>Kurs kayıtları</h2></div><div v-if="detail.enrollments.length" class="enrollment-list"><RouterLink v-for="enrollment in detail.enrollments" :key="enrollment.id" :to="`/courses/${enrollment.courseId}`"><div><strong>{{ enrollment.courseName }}</strong><span>{{ enrollment.status==='active'?'Aktif':'Geçmiş / iptal' }}</span></div><strong :class="{'text-danger':enrollment.balanceCents>0}">{{ money(enrollment.balanceCents) }}</strong></RouterLink></div><StatePanel v-else state="empty" title="Kurs kaydı yok" /></section></aside></div>
    <section class="card statement-card"><div class="card__header"><div><h2>Hesap ekstresi</h2><span class="muted">Üyelik ve kurs hareketleri tek bakiyede</span></div><RouterLink class="button button--secondary" :to="{path:'/payments',query:{query:detail.participant.fullName}}">Finans defterinde aç</RouterLink></div><div v-if="statementRows.length" class="table-wrap"><table class="data-table statement-table"><thead><tr><th>Tarih</th><th>Açıklama</th><th>Borçlandırma</th><th>Tahsilat</th><th>Bakiye</th><th>Makbuz</th><th>Durum</th></tr></thead><tbody><tr v-for="item in statementRows" :key="`${item.kind}-${item.id}`" :class="{'statement-row--voided':item.status==='voided'}"><td>{{ shortDate(item.occurredAt) }}</td><td><strong>{{ item.description }}</strong><span v-if="item.recordedBy" class="statement-staff">{{ item.recordedBy }}</span></td><td>{{ item.direction==='charge'?money(item.amountCents):'—' }}</td><td>{{ item.direction==='payment'?money(item.amountCents):'—' }}</td><td><strong :class="{'text-danger':item.balanceCents>0}">{{ money(item.balanceCents) }}</strong></td><td>{{ item.receiptNumber||'—' }}</td><td><StatusBadge :tone="item.status==='recorded'?'success':'neutral'" :label="item.status==='recorded'?'Kayıtlı':'Geçersiz'" /><span v-if="item.voidReason" class="statement-staff">{{ item.voidReason }}</span></td></tr></tbody></table></div><StatePanel v-else state="empty" title="Hesap hareketi yok" message="Paket veya kurs kaydı oluştuğunda hesap ekstresi burada görünür." /></section>
    <p class="audit-note">Paket silme yerine iptal kullanılır; tahsilat geçmişi, açık bakiye ve denetim izi korunur.</p>
  </template>
